func (e AppUpdateEvent) EventName() string {
	return metadata.GetEventName(metadata.EventType{Subsystem: AppEventSubsystem, Name: AppUpdateEventName, Version: "v2"})
}

func (e AppUpdateEvent) EventMetadata() metadata.EventMetadata {
	appBase := e.AppBase.GetAppBase()
	resourcePath := metadata.ComposeResourcePath(appBase.Namespace, metadata.EntityApp, appBase.ID)
	return metadata.EventMetadata{ID: ulid.Make().String(), Source: resourcePath, Subject: resourcePath, Time: appBase.UpdatedAt}
}

func (i ListCustomersInput) Validate() error {
	var errs []error
	if i.Namespace == "" { errs = append(errs, models.NewGenericValidationError(errors.New("namespace is required"))) }
	if i.Key != nil {
		if err := i.Key.Validate(); err != nil { errs = append(errs, models.NewGenericValidationError(fmt.Errorf("invalid key filter: %w", err))) }
	}
	return models.NewNillableGenericValidationError(errors.Join(errs...))
}

func (e Entitlement) IsActive(at time.Time) bool {
	if e.DeletedAt != nil && !at.Before(*e.DeletedAt) { return false }
	if e.ActiveFromTime().After(at) { return false }
	if e.ActiveTo != nil && !at.Before(*e.ActiveTo) { return false }
	if e.ActiveToTime() != nil && e.ActiveFromTime().Equal(*e.ActiveToTime()) { return false }
	return true
}

func (d DeduplicatingCollector) Ingest(ctx context.Context, namespace string, ev event.Event) error {
	isUnique, err := d.Deduplicator.IsUnique(ctx, namespace, ev)
	if err != nil { return fmt.Errorf("checking event uniqueness: %w", err) }
	if isUnique { return d.Collector.Ingest(ctx, namespace, ev) }
	return nil
}

